<template><div class="app-container"><el-tabs v-model="tab"><el-tab-pane label="多人聚餐" name="group"><el-table v-loading="loading" :data="groups"><el-table-column label="房间码" prop="roomCode" width="110"/><el-table-column label="房间名称" prop="title" min-width="180"/><el-table-column label="发起人" prop="ownerName"/><el-table-column label="成员" prop="memberCount" width="80"/><el-table-column label="订单金额" width="110"><template #default="s">￥{{s.row.total||0}}</template></el-table-column><el-table-column label="创建时间" prop="createTime" width="165"/><el-table-column label="状态" width="100"><template #default="s"><el-switch v-model="s.row.status" active-value="1" inactive-value="0" @change="setGroup(s.row)"/></template></el-table-column></el-table><pagination v-show="groupTotal>0" :total="groupTotal" v-model:page="groupQuery.pageNum" v-model:limit="groupQuery.pageSize" @pagination="loadGroups"/></el-tab-pane><el-tab-pane label="情侣空间" name="couple"><el-table v-loading="loading" :data="couples"><el-table-column label="邀请码" prop="inviteCode" width="110"/><el-table-column label="用户A" prop="userAName"/><el-table-column label="用户B" prop="userBName"/><el-table-column label="相恋日期" prop="startDate" width="120"/><el-table-column label="投喂次数" prop="feedCount" width="100"/><el-table-column label="创建时间" prop="createTime" width="165"/><el-table-column label="状态" width="100"><template #default="s"><el-switch v-model="s.row.status" active-value="1" inactive-value="0" @change="setCouple(s.row)"/></template></el-table-column></el-table><pagination v-show="coupleTotal>0" :total="coupleTotal" v-model:page="coupleQuery.pageNum" v-model:limit="coupleQuery.pageSize" @pagination="loadCouples"/></el-tab-pane></el-tabs></div></template>
<script setup>import{listGroupRooms,listCoupleSpaces,updateGroupStatus,updateCoupleStatus}from'@/api/kitchen/social';const{proxy}=getCurrentInstance();const tab=ref('group'),loading=ref(false),groups=ref([]),couples=ref([]),groupTotal=ref(0),coupleTotal=ref(0),groupQuery=reactive({pageNum:1,pageSize:10}),coupleQuery=reactive({pageNum:1,pageSize:10});function loadGroups(){loading.value=true;listGroupRooms(groupQuery).then(r=>{groups.value=r.rows||[];groupTotal.value=r.total||0}).finally(()=>loading.value=false)}function loadCouples(){loading.value=true;listCoupleSpaces(coupleQuery).then(r=>{couples.value=r.rows||[];coupleTotal.value=r.total||0}).finally(()=>loading.value=false)}function setGroup(r){updateGroupStatus({id:r.id,status:r.status}).then(()=>proxy.$modal.msgSuccess('房间状态已更新')).catch(()=>r.status=r.status==='1'?'0':'1')}function setCouple(r){updateCoupleStatus({id:r.id,status:r.status}).then(()=>proxy.$modal.msgSuccess('情侣空间状态已更新')).catch(()=>r.status=r.status==='1'?'0':'1')}loadGroups();loadCouples()</script>
